body:
hi, i am using iverilog as a quick syntax checker for a big xilinx vivado project, this works very well, I greatly appreciate your work! 5 seconds vs 5 minutes to find a missing comma makes a big difference.

I would like to report another failure case where vivado is happy and code works, but ivl reports an error. I am not 100% sure if my code is valid verlog. IANAL.

Here is the example errors:
```
common/hdl/ds20k/gdm_busy_veto.sv:50: warning: @* is sensitive to all 12 words in array 'qsfp_rx_bsy_counter'.
common/hdl/ds20k/gdm_busy_veto.sv:51: warning: @* is sensitive to all 12 words in array 'qsfp_rx_bsy_counter'.
common/hdl/ds20k/gdm_busy_veto.sv:56: warning: @* is sensitive to all 12 words in array 'qsfp_rx_bsy_counter'.
common/hdl/ds20k/gdm_busy_veto.sv:44: warning: 'qsfp_rx_bsy_counter' is driven by more than one process.
common/hdl/ds20k/gdm_busy_veto.sv:44: warning: 'qsfp_rx_bsy_counter_latched_out' is driven by more than one process.
common/hdl/ds20k/gdm_busy_veto.sv:44: sorry: Cannot synthesize signals that are driven by more than one process.
```

Here is the source code and full error messages:
```
daq00:ds-dm-gcdm$ cat common/hdl/ds20k/gdm_busy_veto.sv
`default_nettype none

module gdm_busy_veto
  (
   input wire        clk,
   input wire        reset,
   input wire [63:0] ts64,
   input wire        cmd_latch,
   input wire [11:0] qsfp_rx_bsy,
   input wire        qsfp_bsy_force,
   input wire [11:0] qsfp_mask,
   input wire [15:0] vx_bsy_extend,
   input wire [15:0] gdm_veto_extend,
   output reg        gdm_veto_out,
   output reg        gdm_veto_pulse_out,
   output reg [15:0] gdm_veto_pulse_counter_latched_out,
   output reg [15:0] gdm_veto_up_counter_latched_out,
   output reg        gdm_busy_encode_error_latch_out,
   output reg [15:0] pkt16_data_out,
   output reg        pkt16_eop_out,
   output reg        pkt16_valid_out,
   input wire        pkt16_ready,
   output reg        gdm_bsy_out,
   output reg [15:0] gdm_bsy_up_counter_latched_out,
   output reg [15:0] gdm_bsy_pulse_counter_latched_out,
   output reg [15:0] gdm_bsy_refresh_counter_latched_out,
   output reg [7:0]  qsfp_rx_bsy_counter_latched_out[11:0],
   output reg [31:0] gdm_bsy_status_latched_out
   );

   reg               gdm_veto;

   //////////////////////////////////////////////////////////////////
   // GDM busy logic
   //////////////////////////////////////////////////////////////////

   genvar     iqsfp;

   // counters 0 to 255, reset at run start

   reg [7:0]  qsfp_rx_bsy_counter[11:0];

   for (iqsfp = 0; iqsfp < 12; iqsfp++) begin
      always_ff @(posedge clk) begin
         if (reset) begin
            qsfp_rx_bsy_counter[iqsfp] <= 0;
            qsfp_rx_bsy_counter_latched_out[iqsfp] <= 0;
         end else begin
            if (qsfp_rx_bsy[iqsfp]) begin
               if (qsfp_rx_bsy_counter[iqsfp] != 8'hFF) begin
                  qsfp_rx_bsy_counter[iqsfp] <= qsfp_rx_bsy_counter[iqsfp] + 1;
               end
            end

            if (cmd_latch) begin
               qsfp_rx_bsy_counter_latched_out[iqsfp] <= qsfp_rx_bsy_counter[iqsfp];
               qsfp_rx_bsy_counter[iqsfp] <= 0;
            end
         end
      end
   end

   // combined and regenerated from pulse to level

   wire         qsfp_rx_bsy_or = qsfp_bsy_force | |(qsfp_rx_bsy & qsfp_mask);

   reg [16:0]   gdm_bsy_extend_counter; // to ensure cdm_bsy and gdm_bsy overlap, gdm_bsy_counter is twice the length of cdm_bsy_counter

   reg          gdm_bsy;
   reg          gdm_bsy_old;

   reg [15:0]   gdm_bsy_up_counter;
   reg [15:0]   gdm_bsy_pulse_counter;
   reg [15:0]   gdm_bsy_refresh_counter;

   reg [15:0]   gdm_bsy_up_counter_latched;
   reg [15:0]   gdm_bsy_pulse_counter_latched;
   reg [15:0]   gdm_bsy_refresh_counter_latched;

   always_ff @(posedge clk) begin
      if (reset) begin
         gdm_bsy_extend_counter  <= 0;
         gdm_bsy_up_counter      <= 0;
         gdm_bsy_pulse_counter   <= 0;
         gdm_bsy_refresh_counter <= 0;
         gdm_bsy                 <= 0;
      end else begin
         gdm_bsy_old <= gdm_bsy;

         if (qsfp_rx_bsy_or) begin // keep busy, restart counter as long as we receive busy pulse from CDM
            if (gdm_bsy == 0) begin
               if (gdm_bsy_up_counter != 16'hFFFF) begin
                  gdm_bsy_up_counter      <= gdm_bsy_up_counter + 1;
               end
            end else begin
               if (gdm_bsy_refresh_counter != 16'hFFFF) begin
                  gdm_bsy_refresh_counter <= gdm_bsy_refresh_counter + 1;
               end
            end
            gdm_bsy <= 1;
            gdm_bsy_extend_counter[0]    <= 0;
            gdm_bsy_extend_counter[16:1] <= vx_bsy_extend;
            if (gdm_bsy_pulse_counter != 16'hFFFF) begin
               gdm_bsy_pulse_counter        <= gdm_bsy_pulse_counter + 1;
            end
         end else if (gdm_bsy_extend_counter == 0) begin // counter has run out
            gdm_bsy <= 0;
            gdm_bsy_extend_counter <= 0;
         end else begin // counter is running
            gdm_bsy <= 1;
            gdm_bsy_extend_counter <= gdm_bsy_extend_counter - 1;
         end

         if (cmd_latch) begin
            gdm_bsy_up_counter_latched      <= gdm_bsy_up_counter;
            gdm_bsy_pulse_counter_latched   <= gdm_bsy_pulse_counter;
            gdm_bsy_refresh_counter_latched <= gdm_bsy_refresh_counter;
            gdm_bsy_up_counter              <= 0;
            gdm_bsy_pulse_counter           <= 0;
            gdm_bsy_refresh_counter         <= 0;
         end
      end // else: !if(reset || ts_reset_armed)
   end // always_ff @ (posedge clk)

   // gdm_busy_status_latched register

   reg [11:0] qsfp_rx_bsy_collect;
   reg        gdm_bsy_collect;
   reg        gdm_veto_collect;

   reg [31:0] gdm_bsy_status_latched;

   always_ff @(posedge clk) begin
      if (reset) begin
         gdm_bsy_status_latched <= 0;
         qsfp_rx_bsy_collect    <= 0;
         gdm_bsy_collect        <= 0;
         gdm_veto_collect       <= 0;
      end else if (cmd_latch) begin
         gdm_bsy_status_latched[11:0]  <= qsfp_rx_bsy[11:0];
         gdm_bsy_status_latched[23:12] <= qsfp_rx_bsy_collect[11:0];
         gdm_bsy_status_latched[24]    <= gdm_bsy;
         gdm_bsy_status_latched[25]    <= gdm_bsy_collect;
         gdm_bsy_status_latched[26]    <= gdm_veto;
         gdm_bsy_status_latched[27]    <= gdm_veto_collect;
         gdm_bsy_status_latched[28]    <= 0;
         gdm_bsy_status_latched[29]    <= 0;
         gdm_bsy_status_latched[30]    <= 0;
         gdm_bsy_status_latched[31]    <= 0;

         qsfp_rx_bsy_collect <= 0;
         gdm_bsy_collect     <= 0;
         gdm_veto_collect    <= 0;
      end else begin
         qsfp_rx_bsy_collect <= qsfp_rx_bsy_collect   | qsfp_rx_bsy;
         gdm_bsy_collect     <= gdm_bsy_collect  | gdm_bsy;
         gdm_veto_collect    <= gdm_veto_collect | gdm_veto;
      end
   end

   wire gdm_bsy_pulse_up   = gdm_bsy & (!gdm_bsy_old);
   wire gdm_bsy_pulse_down = (!gdm_bsy) & gdm_bsy_old;

   //////////////////////////////////////////////////////////////////
   // GDM veto logic
   //////////////////////////////////////////////////////////////////

   always_ff @(posedge clk) begin
      gdm_veto <= gdm_bsy;
   end

   reg gdm_veto_pulse;
   reg gdm_veto_old;

   // convert from level gdm_veto to pulse gdm_veto_pulse

   reg [15:0]   gdm_veto_extend_counter;


   reg [15:0]   gdm_veto_pulse_counter;
   reg [15:0]   gdm_veto_up_counter;

   reg [15:0]   gdm_veto_pulse_counter_latched;
   reg [15:0]   gdm_veto_up_counter_latched;

   always_ff @(posedge clk) begin
      if (reset) begin
         gdm_veto_extend_counter <= 0;
         gdm_veto_up_counter     <= 0;
         gdm_veto_pulse_counter_latched <= 0;
         gdm_veto_up_counter_latched <= 0;
         gdm_veto_pulse_counter  <= 0;
         gdm_veto_pulse          <= 0;
         gdm_veto_old            <= 0;
      end else begin
         gdm_veto_old <= gdm_veto;

         if (gdm_veto & !gdm_veto_old) begin // gdm_veto 0->1
            gdm_veto_pulse <= 1;
            gdm_veto_extend_counter <= gdm_veto_extend;
            if (gdm_veto_up_counter != 16'hFFFF) begin
               gdm_veto_up_counter     <= gdm_veto_up_counter + 1;
            end
            if (gdm_veto_pulse_counter != 16'hFFFF) begin
               gdm_veto_pulse_counter  <= gdm_veto_pulse_counter + 1;
            end
         end else if (gdm_veto == 0) begin // not bsy
            gdm_veto_pulse <= 0;
            gdm_veto_extend_counter <= 0;
         end else if (gdm_veto_extend_counter == 0) begin // still busy, counter has run out
            gdm_veto_pulse <= 1;
            gdm_veto_extend_counter <= gdm_veto_extend;
            if (gdm_veto_pulse_counter != 16'hFFFF) begin
               gdm_veto_pulse_counter  <= gdm_veto_pulse_counter + 1;
            end
         end else begin // still busy, counter is running
            gdm_veto_pulse <= 0;
            gdm_veto_extend_counter <= gdm_veto_extend_counter - 1;
         end

         if (cmd_latch) begin
            gdm_veto_up_counter_latched    <= gdm_veto_up_counter;
            gdm_veto_pulse_counter_latched <= gdm_veto_pulse_counter;
            gdm_veto_up_counter    <= 0;
            gdm_veto_pulse_counter <= 0;
         end
      end
   end

   //////////////////////////////////////////////////////////////////
   // GDM busy packet generator
   //////////////////////////////////////////////////////////////////

   reg [7:0] gdm_busy_packet_counter;

   reg [15:0] gdm_busy_data;

   assign gdm_busy_data[11:0]  = qsfp_rx_bsy[11:0];
   assign gdm_busy_data[12]    = gdm_bsy;
   assign gdm_busy_data[13]    = gdm_veto;
   assign gdm_busy_data[14]    = 0;
   assign gdm_busy_data[15]    = 0;

   wire [95:0] gdm_busy_packet = { // 16*6 = 96 bits
      gdm_busy_data, // 16 bits = 1 words
      ts64, // 64 bits = 4 words
      gdm_busy_packet_counter[7:0], 8'h84 // 8+8 = 16 bits = 1 word
   };

   wire [15:0]  gdm_busy_pkt16_data;
   wire         gdm_busy_pkt16_eop;
   wire         gdm_busy_pkt16_valid;
   wire         gdm_busy_pkt16_ready;

   wire         gdm_busy_encode_error;

   wire         gdm_busy_packet_pulse = gdm_bsy_pulse_up || gdm_bsy_pulse_down;

   always_ff @(posedge clk) begin
      if (reset) begin
         gdm_busy_packet_counter <= 0;
      end else begin
         if (gdm_busy_packet_pulse) begin
            gdm_busy_packet_counter <= gdm_busy_packet_counter + 1;
         end
      end
   end

   pkt16_encode #(.N(96)) gdm_busy_encode
     (
      .clk(clk),
      .reset(reset),
      .start(gdm_busy_packet_pulse),
      .bits(gdm_busy_packet),
      .pkt16_data_out(  gdm_busy_pkt16_data),
      .pkt16_eop_out(   gdm_busy_pkt16_eop),
      .pkt16_valid_out( gdm_busy_pkt16_valid),
      .pkt16_ready(     gdm_busy_pkt16_ready),
      .error_out(gdm_busy_encode_error) // latched, reported
      );

   reg          gdm_busy_encode_error_latch;

   always_ff@ (posedge clk) begin
      if (reset) begin
         gdm_busy_encode_error_latch <= 0;
      end else begin
         gdm_busy_encode_error_latch <= gdm_busy_encode_error_latch | gdm_busy_encode_error;
      end
   end

   wire              fifo_empty;
   wire              fifo_full;

   assign     gdm_busy_pkt16_ready = ~fifo_full;
   assign     pkt16_valid_out = ~fifo_empty;

   fifo_17_512 fifo
     (
      .clk(clk),
      .srst(reset),
      .wr_rst_busy(),
      .rd_rst_busy(),
      .din({gdm_busy_pkt16_eop,gdm_busy_pkt16_data[15:0]}),
      .wr_en(gdm_busy_pkt16_valid & gdm_busy_pkt16_ready),
      .rd_en(pkt16_valid_out & pkt16_ready),
      .dout({pkt16_eop_out,pkt16_data_out}),
      .empty(fifo_empty),
      .full(fifo_full)
      );

   assign  gdm_busy_encode_error_latch_out = gdm_busy_encode_error_latch;

   assign gdm_bsy_out = gdm_bsy;

   assign gdm_bsy_status_latched_out = gdm_bsy_status_latched;

   assign gdm_bsy_up_counter_latched_out = gdm_bsy_up_counter_latched;
   assign gdm_bsy_pulse_counter_latched_out = gdm_bsy_pulse_counter_latched;
   assign gdm_bsy_refresh_counter_latched_out = gdm_bsy_refresh_counter_latched;

   assign gdm_veto_out = gdm_veto;
   assign gdm_veto_pulse_out = gdm_veto_pulse;

   assign gdm_veto_pulse_counter_latched_out = gdm_veto_pulse_counter_latched;
   assign gdm_veto_up_counter_latched_out    = gdm_veto_up_counter_latched;


endmodule // gdm_busy_veto
